previewCss:
.darma-loader-cssloaders-github-23 {
  display: inline-block;
  width: 58px;
  height: 58px;
  border-radius: 50%;
  border: 4px solid color-mix(in srgb, var(--loader-secondary-color) 35%, transparent);
  border-top-color: var(--loader-color);
  border-right-color: var(--loader-color);
  animation: darma-loader-cssloaders-github-23-spin 1.1400000000000001s cubic-bezier(.55,.15,.45,.85) infinite;
}
.darma-loader-cssloaders-github-23::after {
  content: "";
  display: block;
  width: calc(100% - 16px);
  height: calc(100% - 16px);
  margin: 4px;
  border-radius: 50%;
  border: 3px solid transparent;
  border-bottom-color: var(--loader-secondary-color);
  animation: darma-loader-cssloaders-github-23-spin 0.80s linear infinite reverse;
}
@keyframes darma-loader-cssloaders-github-23-spin { to { transform: rotate(360deg); } }

